class WebSocketServer:
    def __init__(self, ssid=None, password=None, port=80, led_pin=2):
        self.ssid = ssid
        self.password = password
        self.port = port
        self.ip = None
        self.ap = None
        self.sta = None
        self.sock = None
        self.clients = []
        self.device_on = False
